<!DOCTYPE html>
<html>
<head>
<title>WastedToken Mint</title>
<style>
body {
  font-family: sans-serif;
  margin: 0;
  overflow: hidden;
}

#hero {
  width: 100vw;
  height: 100vh;
  background-color: #222;
}

#coin-hero {
  width: 300px;
  height: 300px;
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
}

.edition {
  display: inline-block;
  margin: 20px;
  text-align: center;
}

.edition-canvas {
  width: 100px;
  height: 100px;
}

.buy {
  background-color: #ff6b6b;
  color: white;
  border: none;
  padding: 10px 20px;
  cursor: pointer;
  font-size: 16px;
  transition: background-color 0.3s ease;
}

.buy:hover {
  background-color: #e64a4a;
}
</style>
</head>
<body>

<div id="hero">
  <canvas id="coin-hero"></canvas>

  <div class="edition" data-edition="bronze" data-state="available">
    <canvas class="edition-canvas"></canvas>
    <button class="buy">Add to cart</button>
  </div>
  <div class="edition" data-edition="silver" data-state="available">
    <canvas class="edition-canvas"></canvas>
    <button class="buy">Add to cart</button>
  </div>
  <div class="edition" data-edition="gold" data-state="sold-out">
    <canvas class="edition-canvas"></canvas>
    <button class="buy" disabled>SOLD OUT</button>
  </div>
  <div class="edition" data-edition="black" data-state="coming-soon">
    <canvas class="edition-canvas"></canvas>
    <button class="buy">Add to cart</button>
  </div>
</div>

<script>
const canvas = document.getElementById('coin-hero');
const ctx = canvas.getContext('2d');
ctx.fillStyle = '#222';
ctx.fillRect(0, 0, canvas.width, canvas.height);

let angle = 0;
let specularAngle = 0;
let specularSpeed = 0.01;

function renderFrame() {
  angle += 0.05;
  specularAngle += specularSpeed;

  ctx.clearRect(0, 0, canvas.width, canvas.height);

  // Coin Face 1 (Embossed)
  ctx.save();
  ctx.translate(canvas.width / 2, canvas.height / 2);
  ctx.rotate(angle);
  ctx.fillStyle = '#ddd';
  ctx.beginPath();
  ctx.ellipse(0, 0, 150, 150);
  ctx.fill();

  // Emblem (Simplified)
  ctx.fillStyle = '#fff';
  ctx.fillRect(-75, -75, 150, 150);


  // Coin Face 2 (Token Count)
  ctx.rotate(angle * 0.5);
  ctx.translate(0, -100); // Offset for the back face
  ctx.fillStyle = '#ddd';
  ctx.beginPath();
  ctx.ellipse(0, 0, 150, 150);
  ctx.fill();

  // Token Count (Simplified)
  ctx.fillStyle = '#fff';
  ctx.font = '24px sans-serif';
  ctx.textAlign = 'center';
  ctx.fillText('10,000 TOKENS', 0, 0);


  // Reeded Edge (Simple lines)
  ctx.strokeStyle = '#888';
  ctx.lineWidth = 3;
  ctx.beginPath();
  ctx.arc(0, 0, 150, 0, 2 * Math.PI);
  ctx.stroke();

  // Specular Highlight (Simple radial gradient)
  ctx.fillStyle = 'rgba(255, 255, 255, 0.3)';
  ctx.beginPath();
  ctx.arc(0, 0, 75, 0, 2 * Math.PI);
  ctx.fill();

  ctx.restore();
}


window.demo = {
  canvas,
  setTime: (t) => {
    angle = t;
    specularAngle = t;
    renderFrame();
  },
  pause: () => {
    cancelAnimationFrame(animationId);
  }
};

const animationId = requestAnimationFrame(renderFrame);
</script>

</body>
</html>
